// ════════════════════════════════════════════════════════
// HASH DE SENHAS — SHA-256 (SubtleCrypto ou fallback)
// ════════════════════════════════════════════════════════
async function hashPassword(pass) {
  let h = 0;
  const s = pass + 'nagumo_salt_2025';
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h + s.charCodeAt(i)) | 0;
  }
  const h2 = Math.abs(h).toString(16).padStart(8, '0');
  let h3 = 0;
  for (let i = s.length - 1; i >= 0; i--) {
    h3 = ((h3 << 5) - h3 + s.charCodeAt(i)) | 0;
  }
  return h2 + Math.abs(h3).toString(16).padStart(8, '0') + h2.split('').reverse().join('') + Math.abs(h ^ h3).toString(16).padStart(8, '0');
}

async function checkPass(store, userId, plainPass) {
  let user = store.users?.[userId];
  if (!user) {
    user = (store.employees||[]).find(e => e.login_id === userId || String(e.id) === String(userId));
  }
  if (!user) return false;
  const hash = await hashPassword(plainPass);
  if (user.pass === hash) return true;
  if (user.pass && user.pass.length !== 32) {
    const upgraded = await hashPassword(user.pass);
    if (upgraded === hash) return true;
  }
  return false;
}

async function upgradePasswords(store) {
  let changed = false;
  for (const id of Object.keys(store.users || {})) {
    const u = store.users[id];
    if (u.pass && u.pass.length !== 32) {
      u.pass = await hashPassword(u.pass);
      changed = true;
    }
  }
  if (changed) await saveStore(store);
}

// ════════════════════════════════════════════════════════
// STORAGE — duas camadas
// ════════════════════════════════════════════════════════

// ── LS_LOCAL: localStorage síncrono (sessão + tema + overrides) ──────────
// Dados que são POR DISPOSITIVO/NAVEGADOR e não precisam ser compartilhados.
const LS_LOCAL = {
  get:    (k, def=null) => { try { const v=localStorage.getItem(k); return v!==null?JSON.parse(v):def; } catch(e){return def;} },
  set:    (k, v)        => { try { localStorage.setItem(k, JSON.stringify(v)); } catch(e){} },
  remove: (k)           => { try { localStorage.removeItem(k); } catch(e){} },
};

// ── LS: localStorage assíncrono (delega para window.DB) ─────────────────
const LS = {
  get:    async (k, def=null) => await window.DB.get(k, def),
  set:    async (k, v)        => await window.DB.set(k, v),
  remove: async (k)           => await window.DB.remove(k),
};

// ════════════════════════════════════════════════════════
// STORE — objeto principal de dados (localStorage)
// ════════════════════════════════════════════════════════

let _mem = null, _memT = 0, _memRaw = null;

async function getStore() {
  const currentRaw = localStorage.getItem('rh_store');
  if (_mem && currentRaw === _memRaw && (Date.now() - _memT) < 5000) return _mem;
  try {
    const store = await LS.get('rh_store', {
      users:    {},
      config:   { perfWeight:40, aptWeight:35, maxAbs:36, feriadosCustom:[] },
      filiais:  [], turnos:[], depts:[], funcoes:[],
      authCode: AUTH_CODE_DEFAULT,
    });
    _mem = store; _memT = Date.now(); _memRaw = currentRaw;
    if (typeof window._syncPermOverrides === 'function') window._syncPermOverrides(store);
    return store;
  } catch(e) {
    console.error('[getStore] Falha ao ler dados:', e.message || e);
    throw e;
  }
}

async function saveStore(store) {
  try {
    await LS.set('rh_store', store);
    _mem = store; _memT = Date.now(); _memRaw = JSON.stringify(store);
    try { window.dispatchEvent(new CustomEvent('page-refresh')); } catch(e) {}
  } catch(e) {
    console.error('[saveStore] Erro ao salvar:', e);
    if (typeof showToast === 'function') {
      showToast('❌ Falha ao salvar dados!', 'err');
    }
    throw e;
  }
}

var _bootSynced = false;
async function bootSync() {
  if (_bootSynced) return;
  _bootSynced = true;
}

async function ensureAdmin() {
  try {
    const store = await getStore();
    const correctHash = await hashPassword('admin123');
    // Migração: remove admin antigo ('admin') se o novo já existe
    if (store.users['admin'] && store.users[ADMIN_ID]) {
      delete store.users['admin'];
      await saveStore(store);
    }
    if (!store.users[ADMIN_ID]) {
      // Se existe admin antigo com id 'admin', migra para o novo ID
      if (store.users['admin']) {
        const old = Object.assign({}, store.users['admin']);
        old.id = ADMIN_ID;
        old.pass = correctHash;
        store.users[ADMIN_ID] = old;
        delete store.users['admin'];
        await saveStore(store);
        return;
      }
      // Cria admin mesmo se já existem outros usuários
      store.users[ADMIN_ID] = {
        id: ADMIN_ID, name:'Administrador', pass:correctHash, avatar:null,
        nivel:'admin_master', setor:'',
        perfil:{ filial:'', turno:'', depts:[] },
      };
      await saveStore(store);
    } else if (store.users[ADMIN_ID].pass !== correctHash) {
      store.users[ADMIN_ID].pass = correctHash;
      await saveStore(store);
    }
  } catch(e) {
    console.error('[ensureAdmin] Erro:', e);
  }
}

// ════════════════════════════════════════════════════════
// SESSÃO — usa LS_LOCAL (síncrono, por dispositivo)
// ════════════════════════════════════════════════════════
async function getSession() {
  const id = LS_LOCAL.get('rh_session');
  if (!id) return null;
  const store = await getStore();
  if (store.users?.[id]) return store.users[id];
  const emp = (store.employees||[]).find(e => e.login_id === id && e.nivel);
  return emp || null;
}

function _redirectLogin() {
  if (window.parent !== window) {
    window.parent.location.href = '../login.html';
  } else {
    window.location.href = '../login.html';
  }
}

async function requireSession() {
  try {
    await bootSync();
    await ensureAdmin();
    const user = await getSession();
    if (!user) { _redirectLogin(); return null; }
    return user;
  } catch(e) {
    console.error('[requireSession] Falha ao carregar sessão:', e);
    _mostrarTelaErro();
    return null;
  }
}

function _mostrarTelaErro() {
  document.body.style.cssText = 'margin:0;background:#0b0d14;display:flex;align-items:center;justify-content:center;height:100vh;';
  document.body.innerHTML = `
    <div style="text-align:center;font-family:system-ui,sans-serif;color:#e2e8f0;padding:32px;">
      <div style="font-size:3.5rem;margin-bottom:16px;">⚠️</div>
      <h2 style="margin:0 0 8px;font-size:1.4rem;color:#f87171;">Erro ao carregar</h2>
      <p style="color:#94a3b8;margin:0 0 24px;font-size:0.95rem;max-width:300px;">
        Ocorreu um erro ao carregar os dados.<br>Tente novamente.
      </p>
      <button onclick="location.reload()"
        style="padding:10px 28px;background:#4f8ef7;color:#fff;border:none;border-radius:10px;
               font-size:0.95rem;cursor:pointer;font-weight:600;">
        🔄 Tentar novamente
      </button>
    </div>`;
}

function doLogout() {
  if (!confirm('Deseja sair?')) return;
  LS_LOCAL.remove('rh_session');   // síncrono — localStorage
  _redirectLogin();
}

