// ════════════════════════════════════════════════════════
// TOAST
// ════════════════════════════════════════════════════════
let _pageReady = false;
document.addEventListener('DOMContentLoaded', () => {
  setTimeout(() => { _pageReady = true; }, 1500);
});

// ── Loading screen ──
let _loadingFallback = setTimeout(() => {
  const ls = document.getElementById('loading-screen');
  if (ls) ls.classList.add('hide');
}, 5000);
function hideLoading() {
  clearTimeout(_loadingFallback);
  const ls = document.getElementById('loading-screen');
  if (ls) ls.classList.add('hide');
}

function showToast(msg, type='ok') {
  if (!_pageReady && type !== 'ok') return;
  let c = document.getElementById('toast-container');
  if (!c) {
    c = document.createElement('div');
    c.id = 'toast-container';
    c.style.cssText = 'position:fixed;bottom:24px;right:24px;z-index:99999;display:flex;flex-direction:column;gap:8px;pointer-events:none';
    document.body.appendChild(c);
  }
  const t = document.createElement('div');
  t.className = `toast ${type}`;
  t.textContent = msg;
  t.style.pointerEvents = 'auto';
  c.appendChild(t);
  setTimeout(() => t.remove(), 3500);
}

// ════════════════════════════════════════════════════════
// TEMA — usa LS_LOCAL (síncrono, preferência local por dispositivo)
// ════════════════════════════════════════════════════════
function initTheme() {
  const isLight = LS_LOCAL.get('rh_theme') === 'light';
  // Aplica no <html> (para compatibilidade com o script anti-flash do <head>)
  // e no <body> (para os seletores CSS body.light-theme)
  if (isLight) {
    document.documentElement.classList.add('light-theme');
    document.body.classList.add('light-theme');
  } else {
    document.documentElement.classList.remove('light-theme');
    document.body.classList.remove('light-theme');
  }
  syncThemeButtons();
}

function toggleTheme() {
  const isLight = document.body.classList.toggle('light-theme');
  document.documentElement.classList.toggle('light-theme', isLight);
  LS_LOCAL.set('rh_theme', isLight ? 'light' : 'dark');
  syncThemeButtons();
}

function syncThemeButtons() {
  const isLight = document.body.classList.contains('light-theme');
  document.querySelectorAll('.theme-toggle-btn').forEach(b => b.classList.toggle('light-on', isLight));
  document.querySelectorAll('.theme-toggle-label').forEach(l => {
    l.textContent = isLight ? '🌙 Tema Escuro' : '☀️ Tema Claro';
  });
}

// ════════════════════════════════════════════════════════
// SIDEBAR — função única, usada em todas as páginas
// CSS vem do sidebar.css (nunca duplicar nos HTMLs)
// ════════════════════════════════════════════════════════
function initSidebar(activeId, user) {
  const nivel   = user?.nivel || 'lider';
  const meta    = NIVEL_LABELS[nivel] || NIVEL_LABELS['lider'];

  const inPages = window.location.pathname.includes('/pages/');

  // Sempre colapsado — evita expansão ao navegar entre páginas
  document.body.classList.add('sb-collapsed');

  const dashHref = inPages ? '../index.html' : 'index.html';

  const visibleItems = (typeof canSee === 'function')
    ? NAV_ITEMS.filter(item => canSee(user, item.page))
    : NAV_ITEMS;

  const navHtml = visibleItems.map(item => {
    const isActive = item.id === activeId;
    let href;

    if (item.id === 'dashboard') {
      href = dashHref;
    } else if (inPages) {
      href = item.href;
    } else {
      href = 'pages/' + item.href;
    }

    const fsAttr = (!inPages && item.fullscreen)
      ? ` onclick=""`
      : '';

    return `<a class="sb-item ${isActive ? 'active' : ''}" href="${href}"${fsAttr} data-tip="${item.label}" aria-label="${item.label}">
      <span class="sb-icon">${item.icon}</span>
      <span class="sb-label">${item.label}</span>
    </a>`;
  }).join('');

  const sidebar = document.getElementById('app-sidebar');
  if (!sidebar) return;

  sidebar.innerHTML = `
    <div class="sb-brand-icon" data-tip="${user?.name?.split(' ')[0] || 'Usuário'} · ${meta.label}">
      <img src="${NAGUMO_ICON}" alt="Nagumo">
    </div>

    <nav class="sb-nav">${navHtml}</nav>

    <div class="sb-footer">
      <div class="sb-user-info" style="display:flex;align-items:center;gap:10px;padding:10px 14px;border-bottom:1px solid var(--border,#2a2f45);margin-bottom:6px">
        ${user.avatar
          ? `<img src="${user.avatar}" style="width:30px;height:30px;border-radius:50%;object-fit:cover;border:2px solid var(--accent,#4f8ef7);flex-shrink:0">`
          : `<div style="width:30px;height:30px;border-radius:50%;background:var(--accent,#4f8ef7);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;color:#fff;flex-shrink:0">${(user.name||'?')[0]}</div>`
        }
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;font-weight:600;color:var(--text,#fff);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${user.name||'Usuário'}</div>
          <div style="font-size:10px;color:${meta.cor};white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${meta.label}</div>
        </div>
      </div>
      <div class="sb-brand"><center>Sistema Inteligente<br>Gestão de Ponto Nagumo<br>Desenvolvido por<br> Departamento de Inteligência</center></div>
      <button class="sb-logout" onclick="doLogout()">
        <span>🚪</span>
        <span>Sair</span>
      </button>
    </div>`;

  try {
    const _sc = sidebar.cloneNode(true);
    _sc.querySelectorAll('.active').forEach(el => el.classList.remove('active'));
    localStorage.setItem('rh_sb_cache_v2', _sc.innerHTML);
  } catch(e) {}
  _initSidebarTooltip();
}

function _initSidebarTooltip() {
  const old = document.getElementById('_sb-tip');
  if (old) old.remove();

  const tip = document.createElement('div');
  tip.id = '_sb-tip';
  tip.style.cssText = [
    'position:fixed','z-index:99999','pointer-events:none',
    'background:linear-gradient(135deg,#1a1e2e,#12151f)',
    'color:#e2e8f0',
    "font-family:'DM Sans',sans-serif",'font-size:12px','font-weight:600',
    'padding:7px 14px','border-radius:10px',
    'border:1px solid rgba(79,142,247,.3)',
    'box-shadow:0 8px 24px rgba(0,0,0,.6)',
    'white-space:nowrap','letter-spacing:.2px',
    'opacity:0','transition:opacity .18s','top:0','left:0'
  ].join(';');
  document.body.appendChild(tip);

  if (window._sbTipInit) return;
  window._sbTipInit = true;

  document.body.addEventListener('mouseover', e => {
    const t = document.getElementById('_sb-tip');
    if (!t) return;

    const brand = e.target.closest('#app-sidebar .sb-brand-icon[data-tip]');
    const item  = e.target.closest('#app-sidebar .sb-item[data-tip]');

    // brand icon: sempre mostra
    if (brand) {
      const rect = brand.getBoundingClientRect();
      t.textContent = brand.getAttribute('data-tip');
      t.style.top  = (rect.top + rect.height/2 - 14) + 'px';
      t.style.left = (rect.right + 12) + 'px';
      t.style.opacity = '1';
      return;
    }

    // nav item em collapsed: mostra o label da página
    if (item && document.body.classList.contains('sb-collapsed')) {
      const rect = item.getBoundingClientRect();
      t.textContent = item.getAttribute('data-tip');
      t.style.top  = (rect.top + rect.height/2 - 14) + 'px';
      t.style.left = (rect.right + 12) + 'px';
      t.style.opacity = '1';
      return;
    }

    // tudo mais: esconde
    t.style.opacity = '0';
  });

  document.getElementById('app-sidebar')?.addEventListener('mouseleave', () => {
    const t = document.getElementById('_sb-tip');
    if (t) t.style.opacity = '0';
  });
}

function renderSidebar(activeId, user) { initSidebar(activeId, user); }

// ════════════════════════════════════════════════════════
// BLOQUEIO DE AFASTADO / FÉRIAS
// ════════════════════════════════════════════════════════
function getSupervisedEmployees(user, includeDemitidos) {
  if (!user) return [];
  const all = includeDemitidos
    ? (_store?.employees || [])
    : (_store?.employees || []).filter(e => !e.demitido);
  const scope = (typeof dataScope==='function') ? dataScope(user) : { all:true };
  if (scope.all) return all;

  const uid = String(user.id);

  // Filiais que o usuário pode acessar
  const userFiliais = user.perfil?.filiais?.length
    ? user.perfil.filiais
    : (user.filial ? [user.filial] : []);

  // Aplica filtro de filial para níveis abaixo de gerencia/diretoria
  let candidates = all;
  if (userFiliais.length) {
    candidates = all.filter(e => !e.filial || userFiliais.includes(e.filial));
  }

  if (scope.own) {
    return candidates.filter(e => {
      const sid = e.supervisor_id || e.owner_id || e.ownerId;
      if (!sid) return false;
      return String(sid) === uid;
    });
  }

  if (scope.sector) {
    const myLevel = (typeof roleLevel==='function') ? roleLevel(user.nivel||'lider') : 0;
    const myDepts = user?.perfil?.depts || [];
    const allUsers = Object.values(_store?.users || {});
    const subIds = allUsers
      .filter(u => {
        if (String(u.id) === ADMIN_ID || String(u.id) === uid) return false;
        const uLevel = (typeof roleLevel==='function') ? roleLevel(u.nivel||'lider') : 0;
        if (uLevel >= myLevel) return false;
        const ud = u.perfil?.depts || [];
        if (!ud.some(d => myDepts.includes(d))) return false;
        // Subordinado precisa estar nas mesmas filiais
        const uFiliais = u.perfil?.filiais?.length
          ? u.perfil.filiais
          : (u.filial ? [u.filial] : []);
        if (userFiliais.length && uFiliais.length) {
          return uFiliais.some(f => userFiliais.includes(f));
        }
        return true;
      })
      .map(u => String(u.id));
    const valid = new Set([uid, ...subIds]);
    return candidates.filter(e => {
      const sid = e.supervisor_id || e.owner_id || e.ownerId;
      return sid && valid.has(String(sid));
    });
  }
  return [];
}

function isEmpBloqueado(emp) {
  if (!emp.supervisor_id && !emp.owner_id && !emp.ownerId) {
    return { bloqueado: true, motivo: 'sem_dono' };
  }
  const hoje = new Date(); hoje.setHours(0,0,0,0);
  if (emp.afastado) {
    if (emp.data_afastamento) {
      const inicio = new Date(emp.data_afastamento + 'T00:00:00');
      if (inicio <= hoje) return { bloqueado:true, motivo:'afastado' };
    } else {
      return { bloqueado:true, motivo:'afastado' };
    }
  }
  if (emp.maternidade) {
    return { bloqueado:true, motivo:'maternidade' };
  }
  if (emp.ferias && emp.data_ferias_inicio && emp.data_ferias_fim) {
    const ini = new Date(emp.data_ferias_inicio + 'T00:00:00');
    const fim = new Date(emp.data_ferias_fim    + 'T00:00:00');
    if (ini <= hoje && fim >= hoje) return { bloqueado:true, motivo:'ferias' };
  }
  return { bloqueado:false, motivo:null };
}

function isScoreCongelado(emp) {
  return isEmpBloqueado(emp).bloqueado;
}

// ════════════════════════════════════════════════════════
// SCORE HELPERS COMPARTILHADOS
// ════════════════════════════════════════════════════════
const APT_KEYS = ['qual','prio','know','comm','prod','assid','org','equip','cria','motv'];
const MONTHS = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];

function currentMonthKey() {
  const n = new Date();
  return `${n.getFullYear()}-${String(n.getMonth()+1).padStart(2,'0')}`;
}

function getWeights(store) {
  const cfg = (store||{}).config || {};
  let pw = Math.min(80, Math.max(10, parseInt(cfg.perfWeight) || 40));
  let aw = Math.min(80, Math.max(10, parseInt(cfg.aptWeight) || 35));
  if (pw + aw > 90) {
    const sum = pw + aw;
    pw = Math.round(pw * 90 / sum);
    aw = Math.round(aw * 90 / sum);
    if (pw < 10) { pw = 10; aw = 80; }
    if (aw < 10) { aw = 10; pw = 80; }
  }
  return { perf: pw, apt: aw, abs: 100 - pw - aw };
}

function calcAptMedia(emp, monthKey) {
  const mk = monthKey || currentMonthKey();
  const snap = (emp.competencies_history||{})[mk];
  if (snap) return APT_KEYS.reduce((s,k) => s+(snap[k]||0), 0) / APT_KEYS.length;
  const c = emp.competencies || {};
  return APT_KEYS.reduce((s,k) => s+(c[k]||0), 0) / APT_KEYS.length;
}

function calcAssid(emp, maxAbs, totalOverride) {
  if (emp.afastado || emp.maternidade) return 100;
  const total = totalOverride != null ? totalOverride : (emp.absences||[]).reduce((a,b)=>a+b, 0);
  const max = maxAbs || 36;
  return Math.max(0, 100-(total/max)*100);
}

function calcScore(emp, store, bonus) {
  const w = getWeights(store);
  const perf = (emp.perf_history||{})[currentMonthKey()] ?? emp.perf ?? 0;
  const base = perf*(w.perf/100) + calcAptMedia(emp)*10*(w.apt/100) + calcAssid(emp, (store||{}).config?.maxAbs)*(w.abs/100);
  return Math.min(100, Math.round(base + (bonus||0)));
}

function getStatus(score) {
  if (score>=85) return { tag:'promo', label:'🏆 Promoção', cls:'tag-promo' };
  if (score>=70) return { tag:'ok',    label:'✅ Regular',  cls:'tag-ok'    };
  if (score>=55) return { tag:'watch', label:'⚠️ Atenção',  cls:'tag-watch' };
  return               { tag:'risk',  label:'🔴 Risco',    cls:'tag-risk'  };
}

// ════════════════════════════════════════════════════════
// CONFIRM MODAL — modal de confirmação assíncrono
// ════════════════════════════════════════════════════════
function showConfirmModal(msg) {
  return new Promise(function (resolve) {
    const existing = document.getElementById('_confirm-modal');
    if (existing) existing.remove();
    const overlay = document.createElement('div');
    overlay.id = '_confirm-modal';
    overlay.setAttribute('role','dialog');
    overlay.setAttribute('aria-modal','true');
    overlay.style.cssText = 'position:fixed;inset:0;z-index:100000;background:rgba(0,0,0,.6);display:flex;align-items:center;justify-content:center;';
    const dialog = document.createElement('div');
    dialog.style.cssText = 'background:var(--surface,#12151f);border:1px solid var(--border,#2a2f45);border-radius:16px;padding:28px;width:380px;max-width:90vw;box-shadow:0 24px 64px rgba(0,0,0,.5);text-align:center;';
    dialog.innerHTML =
      '<div style="font-size:15px;color:var(--text,#fff);margin-bottom:20px;line-height:1.5">' + msg.replace(/\n/g,'<br>') + '</div>' +
      '<div style="display:flex;gap:8px;justify-content:center">' +
      '<button id="_confirm-cancel" style="padding:8px 20px;background:var(--surface3,#222638);border:1px solid var(--border,#2a2f45);border-radius:10px;color:var(--muted,#94a3b8);font-size:13px;cursor:pointer">Cancelar</button>' +
      '<button id="_confirm-ok" style="padding:8px 20px;background:var(--red,#f87171);border:none;border-radius:10px;color:#fff;font-size:13px;font-weight:600;cursor:pointer">Confirmar</button></div>';
    overlay.appendChild(dialog);
    document.body.appendChild(overlay);
    function close(val) { overlay.remove(); resolve(val); }
    document.getElementById('_confirm-cancel').onclick = function () { close(false); };
    document.getElementById('_confirm-ok').onclick = function () { close(true); };
    overlay.addEventListener('keydown', function (e) { if (e.key === 'Escape') close(false); });
    document.getElementById('_confirm-ok').focus();
  });
}

