function toTitleCase(str) {
  return str.replace(/\S+/g, w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase());
}
function uid() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2,6);
}

// ════════════════════════════════════════════════════════
// AUDIT LOG — assíncrono (grava no localStorage)
// ════════════════════════════════════════════════════════
async function registrarLog(acao, modulo, detalhes, userOverride) {
  try {
    const session = userOverride || await getSession();
    if (!session) return;
    const ua = navigator.userAgent;
    let browser = 'Desconhecido';
    if      (ua.includes('Edg/'))     browser = 'Edge';
    else if (ua.includes('OPR/'))     browser = 'Opera';
    else if (ua.includes('Chrome/'))  browser = 'Chrome';
    else if (ua.includes('Firefox/')) browser = 'Firefox';
    else if (ua.includes('Safari/'))  browser = 'Safari';
    let os = 'Desconhecido';
    if      (ua.includes('Windows')) os = 'Windows';
    else if (ua.includes('Android')) os = 'Android';
    else if (ua.includes('iPhone') || ua.includes('iPad')) os = 'iOS';
    else if (ua.includes('Mac'))     os = 'macOS';
    else if (ua.includes('Linux'))   os = 'Linux';
    const LOG_KEY = 'rh_audit_log';
    const logs    = await LS.get(LOG_KEY, []);
    logs.unshift({
      id:       uid(),
      ts:       new Date().toISOString(),
      userId:   session.id,
      userName: session.name,
      acao, modulo, detalhes,
      device:   `${browser} · ${os}`,
    });
    const corte7d = new Date();
    corte7d.setDate(corte7d.getDate() - 7);
    const filtrado = logs.filter(l => new Date(l.ts) >= corte7d);
    await LS.set(LOG_KEY, filtrado.slice(0, 500));
  } catch(e) {
    console.error('[registrarLog] erro:', e);
  }
}


